use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use reqwest::Client;
use std::net::IpAddr;

const ALLOWED_DOMAINS: [&str; 2] = ["example.com", "api.example.com"];

async fn forward_request(query: web::Query<HashMap<String, String>>, client: web::Data<Client>) -> impl Responder {
    let url = match query.get("url") {
        Some(url) => url,
        None => return HttpResponse::BadRequest().body("Missing 'url' query parameter"),
    };

    if !is_allowed_url(url) {
        return HttpResponse::Forbidden().body("URL not allowed");
    }

    match client.get(url).send().await {
        Ok(response) => {
            let status = response.status();
            let body = response.text().await.unwrap_or_else(|_| "Failed to read response".to_string());
            HttpResponse::build(status).body(body)
        }
        Err(_) => HttpResponse::InternalServerError().body("Error fetching the URL"),
    }
}

fn is_allowed_url(url: &str) -> bool {
    if let Ok(parsed_url) = url::Url::parse(url) {
        let host = parsed_url.host_str().unwrap_or("");
        if ALLOWED_DOMAINS.iter().any(|&domain| host.ends_with(domain)) {
            return !is_internal_ip(parsed_url);
        }
    }
    false
}

fn is_internal_ip(parsed_url: url::Url) -> bool {
    if let Some(ip) = parsed_url.socket_addrs(|| None).ok().and_then(|addrs| addrs.first()).map(|addr| addr.ip()) {
        match ip {
            IpAddr::V4(ipv4) => {
                ipv4.is_private() || ipv4.is_loopback()
            }
            IpAddr::V6(ipv6) => {
                ipv6.is_loopback() || ipv6.is_unique_local()
            }
        }
    } else {
        false
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let client = Client::new();
    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(client.clone()))
            .route("/forward", web::get().to(forward_request))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}